# Hand of Straights — O(n log n) time, O(n) space
# KEY INSIGHT: smallest card always starts a group (greedy)

from collections import Counter
import heapq

def isNStraightHand(hand, groupSize):
    if len(hand) % groupSize != 0:
        return False

    count = Counter(hand)
    min_heap = list(count.keys())
    heapq.heapify(min_heap)

    while min_heap:
        start = min_heap[0]  # smallest remaining card

        for card in range(start, start + groupSize):
            if count[card] == 0:
                return False
            count[card] -= 1
            if count[card] == 0:
                if card != min_heap[0]:
                    return False  # heap top should be card if it hit 0
                heapq.heappop(min_heap)

    return True
